namespace sv_ebdf83f7127448949fe1220d47519f4f.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);

public record Message(
    int Id,
    int ChannelId,
    string Author,
    string Content,
    DateTime SentAt,
    int? ReplyToId,
    List<Reaction> Reactions);

public record Reaction(string Emoji, List<string> Users);

public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_ebdf83f7127448949fe1220d47519f4f.Models;

public static class ChatTimeHelper
{
    public static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat

<div class="emoji-picker" @onclick:stopPropagation>
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "👎"];
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat

<div class="message-input-box">
    <textarea class="form-control" rows="2" placeholder="@Placeholder"
              @bind="Text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="btn btn-primary mt-2" @onclick="Send"
            disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models

<div class="message-item @(_hovered ? "hovered" : "")"
     @onmouseenter="() => _hovered = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <small class="text-muted ms-2">@ChatTimeHelper.FormatRelativeTime(Message.SentAt)</small>
    </div>
    <div class="message-body">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link btn btn-link btn-sm p-0"
                @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="btn btn-sm btn-outline-secondary"
                    @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
                Reply
            </button>
            <button class="btn btn-sm btn-outline-secondary"
                    @onclick="ToggleEmojiPicker">
                React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models

<div class="channel-sidebar">
    <h5 class="sidebar-title">Channels</h5>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <button class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                    @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="d-flex justify-content-between align-items-center">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="badge bg-primary rounded-pill">@channel.UnreadCount</span>
                    }
                </div>
                <small class="text-muted channel-desc">@channel.Description</small>
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnChannelSelected { get; set; }
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-area">
    <div class="message-area-header">
        <h5 class="mb-0"># @ChannelName</h5>
        <small class="text-muted">@ChannelDescription</small>
    </div>

    <div class="message-list" @ref="_messageListRef">
        @if (IsLoadingMore)
        {
            <div class="text-center p-2">
                <small class="text-muted">Loading older messages…</small>
            </div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-compose">
        <MessageInput Placeholder="@($"Message #{ChannelName}")"
                      ButtonText="Send"
                      OnSend="OnSendMessage" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<MessageArea>? _selfRef;

    private int GetReplyCount(int messageId) => ReplyCounts.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _selfRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat/MessageArea.razor.js");
            await _jsModule.InvokeVoidAsync("initScrollListener", _messageListRef, _selfRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose", _messageListRef);
            }
            catch (JSDisconnectedException) { }
            await _jsModule.DisposeAsync();
        }
        _selfRef?.Dispose();
    }
}

const state = new WeakMap();

export function initScrollListener(element, dotNetRef) {
    let loading = false;

    const handler = async () => {
        if (element.scrollTop < 50 && !loading) {
            loading = true;
            const prevHeight = element.scrollHeight;
            await dotNetRef.invokeMethodAsync('OnScrolledToTop');
            // Preserve scroll position after new content is inserted above
            requestAnimationFrame(() => {
                const newHeight = element.scrollHeight;
                element.scrollTop += newHeight - prevHeight;
                loading = false;
            });
        }
    };

    element.addEventListener('scroll', handler);
    state.set(element, handler);

    // Scroll to bottom on init
    element.scrollTop = element.scrollHeight;
}

export function dispose(element) {
    const handler = state.get(element);
    if (handler) {
        element.removeEventListener('scroll', handler);
        state.delete(element);
    }
}

@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <strong>@RootMessage.Author</strong>
            <p class="mb-0 mt-1">@RootMessage.Content</p>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div>
                    <strong>@reply.Author</strong>
                    <small class="text-muted ms-2">@ChatTimeHelper.FormatRelativeTime(reply.SentAt)</small>
                </div>
                <div class="mt-1">@reply.Content</div>
            </div>
        }
    </div>

    <div class="thread-compose">
        <MessageInput Placeholder="Reply…" ButtonText="Reply" OnSend="OnReply" />
    </div>
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback OnClose { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnReply { get; set; }
}

