const state = new WeakMap();

export function initScrollListener(element, dotNetRef) {
    let loading = false;

    const handler = async () => {
        if (element.scrollTop < 50 && !loading) {
            loading = true;
            const prevHeight = element.scrollHeight;
            await dotNetRef.invokeMethodAsync('OnScrolledToTop');
            // Preserve scroll position after new content is inserted above
            requestAnimationFrame(() => {
                const newHeight = element.scrollHeight;
                element.scrollTop += newHeight - prevHeight;
                loading = false;
            });
        }
    };

    element.addEventListener('scroll', handler);
    state.set(element, handler);

    // Scroll to bottom on init
    element.scrollTop = element.scrollHeight;
}

export function dispose(element) {
    const handler = state.get(element);
    if (handler) {
        element.removeEventListener('scroll', handler);
        state.delete(element);
    }
}

