@page "/chat"
@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    SelectedChannelId="_selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="chat-main @(_threadOpen ? "" : "chat-main-expanded")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ReplyCounts="_replyCounts"
                         IsLoadingMore="_isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadOlderMessages" />
        }
    </div>

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = new();
    private bool _isLoadingMore;
    private const int PageSize = 50;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        ComputeReplyCounts();
        CloseThreadSync();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        if (_isLoadingMore || _selectedChannel is null) return;
        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId, _messages.Count, PageSize);

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            ComputeReplyCounts();
        }

        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var idx = _messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = _messages[idx];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == args.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                reactions[existing] = new Reaction(r.Emoji, [.. r.Users, "You"]);
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            _messages[idx] = msg with { Reactions = reactions };
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
        _replyCounts[rootMessageId] = _threadReplies.Count;
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        return Task.CompletedTask;
    }

    private void CloseThreadSync()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _replyCounts[_threadRootMessage.Id] = _threadReplies.Count;
    }

    private void ComputeReplyCounts()
    {
        _replyCounts = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

/* ── Layout ─────────────────────────────────────────── */

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-main {
    flex: 0 0 55%;
    display: flex;
    flex-direction: column;
    min-width: 0;
    transition: flex-basis 0.2s ease;
}

.chat-main-expanded {
    flex: 0 0 80%;
}

/* ── Channel Sidebar ───────────────────────────────── */

::deep .channel-sidebar {
    flex: 0 0 20%;
    display: flex;
    flex-direction: column;
    background: #2b2d42;
    color: #edf2f4;
    min-width: 0;
}

::deep .sidebar-title {
    padding: 1rem;
    margin: 0;
    border-bottom: 1px solid rgba(255,255,255,.1);
}

::deep .channel-list {
    flex: 1;
    overflow-y: auto;
}

::deep .channel-item {
    display: block;
    width: 100%;
    padding: 0.6rem 1rem;
    border: none;
    background: transparent;
    color: inherit;
    text-align: left;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255,255,255,.08);
}

::deep .channel-item.active {
    background: rgba(255,255,255,.12);
    border-left-color: #8d99ae;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    display: block;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    font-size: 0.78rem;
    opacity: 0.7;
}

/* ── Message Area ──────────────────────────────────── */

::deep .message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    min-height: 0;
}

::deep .message-area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

::deep .message-compose {
    border-top: 1px solid #dee2e6;
    padding: 0.75rem 1rem;
    flex-shrink: 0;
}

/* ── Message Item ──────────────────────────────────── */

::deep .message-item {
    position: relative;
    padding: 0.5rem 1rem;
    transition: background 0.1s;
}

::deep .message-item.hovered {
    background: #f8f9fa;
}

::deep .message-author {
    font-size: 0.95rem;
}

::deep .message-body {
    margin-top: 0.15rem;
    line-height: 1.45;
    word-break: break-word;
}

::deep .message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    font-size: 0.82rem;
    background: #fff;
    cursor: default;
}

::deep .thread-link {
    font-size: 0.82rem;
    margin-top: 0.25rem;
    text-decoration: none;
}

::deep .message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.75rem;
    display: flex;
    gap: 0.3rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.2rem;
    box-shadow: 0 1px 4px rgba(0,0,0,.1);
}

::deep .message-actions .btn {
    font-size: 0.78rem;
    padding: 0.15rem 0.5rem;
}

/* ── Emoji Picker ──────────────────────────────────── */

::deep .emoji-picker {
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0,0,0,.12);
    position: absolute;
    right: 0.75rem;
    top: 2rem;
    z-index: 10;
}

::deep .emoji-option {
    background: none;
    border: none;
    font-size: 1.15rem;
    cursor: pointer;
    padding: 0.15rem 0.3rem;
    border-radius: 0.25rem;
    transition: background 0.1s;
}

::deep .emoji-option:hover {
    background: #f0f0f0;
}

/* ── Message Input ─────────────────────────────────── */

::deep .message-input-box {
    display: flex;
    flex-direction: column;
}

::deep .message-input-box .btn {
    align-self: flex-end;
}

/* ── Thread Panel ──────────────────────────────────── */

::deep .thread-panel {
    flex: 0 0 25%;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #dee2e6;
    background: #fff;
    min-width: 0;
    height: 100%;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

::deep .thread-root {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
    flex-shrink: 0;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
}

::deep .thread-reply {
    padding: 0.6rem 1rem;
    border-bottom: 1px solid #f0f0f0;
}

::deep .thread-compose {
    border-top: 1px solid #dee2e6;
    padding: 0.75rem 1rem;
    flex-shrink: 0;
}

