@page "/chat"
@namespace sv_ebdf83f7127448949fe1220d47519f4f.Components.Pages.Chat
@using sv_ebdf83f7127448949fe1220d47519f4f.Models
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    SelectedChannelId="_selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="chat-main @(_threadOpen ? "" : "chat-main-expanded")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ReplyCounts="_replyCounts"
                         IsLoadingMore="_isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadOlderMessages" />
        }
    </div>

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = new();
    private bool _isLoadingMore;
    private const int PageSize = 50;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        ComputeReplyCounts();
        CloseThreadSync();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        if (_isLoadingMore || _selectedChannel is null) return;
        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId, _messages.Count, PageSize);

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            ComputeReplyCounts();
        }

        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var idx = _messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = _messages[idx];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == args.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                reactions[existing] = new Reaction(r.Emoji, [.. r.Users, "You"]);
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            _messages[idx] = msg with { Reactions = reactions };
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
        _replyCounts[rootMessageId] = _threadReplies.Count;
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        return Task.CompletedTask;
    }

    private void CloseThreadSync()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _replyCounts[_threadRootMessage.Id] = _threadReplies.Count;
    }

    private void ComputeReplyCounts()
    {
        _replyCounts = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

